  ('careers.p1_desc', 'vi', 'Học sản phẩm, quy trình, thao tác hệ thống. Tiếp nhận & xử lý yêu cầu khách hàng hàng ngày.'),
  ('careers.p1_desc', 'zh', '学习产品、流程和系统操作。接收并处理客户的日常请求。'),
