  ('express_page.warehouse_desc', 'vi', 'Kho THG cung cấp giải pháp logistics toàn diện cho cả hàng lô và hàng lẻ trên tuyến Trung Quốc - Mỹ.'),
  ('express_page.warehouse_desc', 'zh', 'THG仓库为中美国际路线的批量和零售货物提供全面的物流解决方案。'),
  ('express_page.warehouse_feature1_title', 'en', 'CENTRAL WAREHOUSES'),
  ('express_page.warehouse_feature1_title', 'vi', 'KHO BÃI TRUNG TÂM'),
  ('express_page.warehouse_feature1_title', 'zh', '中央仓库'),
  ('express_page.warehouse_feature1_desc', 'en', '2 warehouses in Dongguan & Shenzhen. Optimizing sea & air routes.'),
  ('express_page.warehouse_feature1_desc', 'vi', '2 kho tại Đông Hoản & Thâm Quyến. Tối ưu hóa tuyến đường biển & hàng không.'),
  ('express_page.warehouse_feature1_desc', 'zh', '东莞和深圳有2个仓库。优化海运和空运路线。'),
