  ('express_page.warehouse_feature2_title', 'vi', 'HỖ TRỢ TUYỆT ĐỐI'),
  ('express_page.warehouse_feature2_title', 'zh', '绝对支持'),
  ('express_page.warehouse_feature2_desc', 'en', 'Counting, Sorting, Barcoding. Product QC, Packaging, Photography.'),
  ('express_page.warehouse_feature2_desc', 'vi', 'Hỗ trợ Kiểm đếm, Phân loại, Dán Barcode. QC sản phẩm, Gia cố đơn hàng, Quay chụp.'),
  ('express_page.warehouse_feature2_desc', 'zh', '支持清点、分类、贴条码、产品QC、包装加固、摄影。'),
  ('express_page.warehouse_feature3_title', 'en', 'SMART SYSTEM'),
  ('express_page.warehouse_feature3_title', 'vi', 'HỆ THỐNG THÔNG MINH'),
  ('express_page.warehouse_feature3_title', 'zh', '智能系统'),
  ('express_page.warehouse_feature3_desc', 'en', 'Barcode management system (WMS) ensures high accuracy.'),
  ('express_page.warehouse_feature3_desc', 'vi', 'Hệ thống quản lý (WMS) bằng barcode đảm bảo độ chính xác cao.'),
  ('express_page.warehouse_feature3_desc', 'zh', '基于条码管理的WMS系统，确保高精确度。'),
  ('express_page.policy_section_title', 'en', 'EXPRESS ORDERS'),
  ('express_page.policy_section_title', 'vi', 'ĐƠN EXPRESS'),
