  ('express_page.line_routes_title', 'en', 'SUMMARY OF SHIPPING ROUTES'),
  ('express_page.line_routes_title', 'vi', 'TỔNG HỢP CÁC LINE VẬN CHUYỂN'),
  ('express_page.line_routes_title', 'zh', '运输线路总览'),
  ('express_page.line_routes_desc', 'en', 'THG Express offers a variety of shipping routes, optimized for each seller''s needs and business model. Whether you operate via POD, dropship, or have your own warehouse, we have the right solution to deliver goods quickly, cost-effectively, and meet delivery standards in the US, EU, and UK markets.'),
  ('express_page.line_routes_desc', 'vi', 'THG Express cung cấp đa dạng line vận chuyển, tối ưu cho từng nhu cầu và mô hình kinh doanh của seller. Dù bạn đang vận hành theo hình thức POD, dropship hay có kho riêng, chúng tôi đều có giải pháp phù hợp giúp hàng đến tay khách nhanh chóng, chi phí hợp lý và đảm bảo tiêu chuẩn giao hàng tại thị trường Mỹ, EU, UK.'),
  ('express_page.line_routes_desc', 'zh', 'THG Express提供多种运输线路，针对每个卖家的需求和商业模式进行优化。无论您是通过POD、代发货运营还是有自己的仓库，我们都有合适的解决方案，可以快速、低成本地将货物送达客户，并满足美国、欧盟和英国市场的交货标准。'),
  ('express_page.get_quote_cta', 'en', 'GET A QUOTE NOW'),
  ('express_page.get_quote_cta', 'vi', 'NHẬN BÁO GIÁ NGAY'),
  ('express_page.get_quote_cta', 'zh', '立即获取报价'),
